import{_ as a,o as r,c as o,ae as t}from"./chunks/framework.BGHOrOyn.js";const s="/gitbook-personnal-docs/assets/2024-01-05_23-50.qkxQmwT9.png",i="/gitbook-personnal-docs/assets/2024-01-05_23-48.DuwxLPU8.png",n="/gitbook-personnal-docs/assets/2024-01-05_23-49.mbvAPMFn.png",l="/gitbook-personnal-docs/assets/2024-01-05_23-41.CcY8qSpx.png",k=JSON.parse('{"title":"macOS Disk Usage Analysis","description":"","frontmatter":{},"headers":[],"relativePath":"readme/mac-os-disk-usage-analysis.md","filePath":"readme/mac-os-disk-usage-analysis.md"}'),m={name:"readme/mac-os-disk-usage-analysis.md"};function p(c,e,d,g,f,u){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="macos-disk-usage-analysis" tabindex="-1">macOS Disk Usage Analysis <a class="header-anchor" href="#macos-disk-usage-analysis" aria-label="Permalink to &quot;macOS Disk Usage Analysis&quot;">​</a></h1><p>I always seem to be running out of storage space on my MacBook.</p><p>I found the default storage analysis tools provided by Apple to be rather underwhelming and basic in comparison to my experience using Ubuntu Linux.</p><p>I felt that Baobab and GParted were much more powerful tools.</p><p>Unfortunately, GParted is not available for macOS.</p><figure><img src="'+s+'" alt=""><figcaption><p>underwhelming OSX default disk usage analysis tool </p></figcaption></figure><figure><img src="'+i+'" alt=""><figcaption></figcaption></figure><figure><img src="'+n+'" alt=""><figcaption></figcaption></figure><p>The solution with a GUI that I found to be useful is a program called Disk Inventory X.</p><p>It is open source, as described here:</p><p><em><mark style="color:yellow;">It is absolutely free and released under the</mark></em> <a href="https://www.gnu.org/copyleft/gpl.html" target="_blank" rel="noreferrer"><em><mark style="color:yellow;">GPL</mark></em></a><em><mark style="color:yellow;">. The layout algorithm is based on</mark></em> <a href="https://kdirstat.sourceforge.net/" target="_blank" rel="noreferrer"><em><mark style="color:yellow;">KDirStat</mark></em></a><em><mark style="color:yellow;">. The idea to develop this program came to me when a fellow of mine showed me his creation</mark></em> <a href="https://windirstat.sourceforge.net/" target="_blank" rel="noreferrer"><em><mark style="color:yellow;">WinDirStat</mark></em></a><em><mark style="color:yellow;">.</mark></em>\\</p><p>It can be downloaded here:</p><p><a href="https://derlien.com/downloads/index.html" target="_blank" rel="noreferrer">https://derlien.com/downloads/index.html</a></p><p>And code viewed here:</p><p><a href="https://gitlab.com/tderlien/disk-inventory-x" target="_blank" rel="noreferrer">https://gitlab.com/tderlien/disk-inventory-x</a></p><figure><img src="'+l+'" alt=""><figcaption></figcaption></figure><p>Thank you for this software, Tjark Derlien.</p>',17)])])}const _=a(m,[["render",p]]);export{k as __pageData,_ as default};
